#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; scanf("%d", &N);
        char s[200005]; scanf("%s", s);
        int freq[26] = {0};
        int first[26]; int last[26];
        for(int i=0;i<26;i++) first[i] = -1, last[i] = -1;
        for(int i=0;i<N;i++){
            int c = s[i]-'a';
            freq[c]++;
            if(first[c]==-1) first[c]=i;
            last[c]=i;
        }
        int mod = N%3;
        int ans = 0;
        if(mod==1) ans = 1; // any single character
        else if(mod==2){
            for(int i=0;i<26;i++) if(freq[i]>=2){ ans = 1; break; }
        }else{ // mod == 0
            for(int i=0;i<26;i++){
                if(freq[i]>=3){ ans = 1; break; }
                if(freq[i]>=2 && last[i]-first[i]>=2){ ans = 1; break; }
            }
        }
        printf(ans?"YES\n":"NO\n");
    }
    return 0;
}

